const { WebSocketServer } = require('ws');
const { createServer } = require('http');
const { readFileSync } = require('fs');
const { join } = require('path');

const PORT = process.env.PORT || 3000;

const https = require('https');
const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_KEY;

// Supabase helper
async function supabaseQuery(path, method='GET', body=null) {
  const opts = {
    method,
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': 'Bearer ' + SUPABASE_KEY,
      'Content-Type': 'application/json',
      'Prefer': method === 'POST' ? 'return=representation' : ''
    }
  };
  if (body) opts.body = JSON.stringify(body);
  const r = await fetch(SUPABASE_URL + path, opts);
  return r.json();
}

// Verify JWT token from Supabase
async function verifyToken(token) {
  try {
    const res = await fetch(SUPABASE_URL + '/auth/v1/user', {
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + token }
    });
    return res.ok ? await res.json() : null;
  } catch(e) { return null; }
}

// Get company credits
async function getCompanyCredits(authId) {
  try {
    const res = await fetch(SUPABASE_URL + '/rest/v1/users?auth_id=eq.' + authId + '&select=company_id,companies(credits_balance,is_active)', {
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
    });
    const data = await res.json();
    return data[0] || null;
  } catch(e) { return null; }
}

// Deduct credits (1 credit = 1 second)
async function deductCredits(companyId, seconds) {
  try {
    await fetch(SUPABASE_URL + '/rest/v1/rpc/deduct_credits', {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ p_company_id: companyId, p_seconds: seconds })
    });
  } catch(e) {}
}

// Log usage
async function logUsage(companyId, apiType, costUsd) {
  try {
    await fetch(SUPABASE_URL + '/rest/v1/usage_logs', {
      method: 'POST',
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ company_id: companyId, api_type: apiType, cost_usd: costUsd })
    });
  } catch(e) {}
}

const OPENAI_KEY = process.env.OPENAI_API_KEY;

const OPENAI_KEY_UNUSED = '';

// Helper: proxy POST to OpenAI
function proxyOpenAI(path, body, res) {
  const data = JSON.stringify(body);
  const options = {
    hostname: 'api.openai.com',
    path: path,
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + OPENAI_KEY,
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(data)
    }
  };
  const req = https.request(options, (apiRes) => {
    res.writeHead(apiRes.statusCode, {
      'Content-Type': apiRes.headers['content-type'] || 'application/json',
      'Access-Control-Allow-Origin': '*'
    });
    apiRes.pipe(res);
  });
  req.on('error', (e) => {
    res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
  });
  req.write(data);
  req.end();
}

// Helper: proxy multipart (Whisper STT)
function proxyWhisper(reqBody, contentType, res) {
  const options = {
    hostname: 'api.openai.com',
    path: '/v1/audio/transcriptions',
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + OPENAI_KEY,
      'Content-Type': contentType,
      'Content-Length': reqBody.length
    }
  };
  const apiReq = https.request(options, (apiRes) => {
    res.writeHead(apiRes.statusCode, {
      'Content-Type': 'application/json',
      'Access-Control-Allow-Origin': '*'
    });
    apiRes.pipe(res);
  });
  apiReq.on('error', (e) => {
    res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
  });
  apiReq.write(reqBody);
  apiReq.end();
}

// Helper: proxy TTS (binary audio)
function proxyTTS(body, res) {
  const data = JSON.stringify(body);
  const options = {
    hostname: 'api.openai.com',
    path: '/v1/audio/speech',
    method: 'POST',
    headers: {
      'Authorization': 'Bearer ' + OPENAI_KEY,
      'Content-Type': 'application/json',
      'Content-Length': Buffer.byteLength(data)
    }
  };
  const req = https.request(options, (apiRes) => {
    res.writeHead(apiRes.statusCode, {
      'Content-Type': 'audio/mpeg',
      'Access-Control-Allow-Origin': '*'
    });
    apiRes.pipe(res);
  });
  req.on('error', (e) => {
    res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
  });
  req.write(data);
  req.end();
}

// Serve the HTML app + proxy routes
const server = createServer((req, res) => {
  // CORS preflight
  if (req.method === 'OPTIONS') {
    res.writeHead(204, {
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Methods': 'POST, GET, OPTIONS',
      'Access-Control-Allow-Headers': 'Content-Type, Authorization'
    });
    res.end();
    return;
  }


  // Register company
  if (req.method === 'POST' && req.url === '/api/register-company') {
    let body = '';
    req.on('data', d => body += d);
    req.on('end', async () => {
      try {
        const { company_name, email, auth_id } = JSON.parse(body);
        // Create company in Supabase
        const compRes = await fetch(SUPABASE_URL + '/rest/v1/companies', {
          method: 'POST',
          headers: {
            'apikey': SUPABASE_KEY,
            'Authorization': 'Bearer ' + SUPABASE_KEY,
            'Content-Type': 'application/json',
            'Prefer': 'return=representation'
          },
          body: JSON.stringify({ name: company_name, email })
        });
        const company = await compRes.json();
        const companyId = company[0]?.id;

        // Create user record
        if (companyId && auth_id) {
          await fetch(SUPABASE_URL + '/rest/v1/users', {
            method: 'POST',
            headers: {
              'apikey': SUPABASE_KEY,
              'Authorization': 'Bearer ' + SUPABASE_KEY,
              'Content-Type': 'application/json'
            },
            body: JSON.stringify({ auth_id, company_id: companyId, email, role: 'admin' })
          });
        }
        res.writeHead(200, { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' });
        res.end(JSON.stringify({ success: true }));
      } catch(e) {
        res.writeHead(500); res.end(JSON.stringify({ error: e.message }));
      }
    });
    return;
  }

  // Proxy: Translation (GPT-4o)
  if (req.method === 'POST' && req.url === '/api/translate') {
    let body = '';
    req.on('data', d => body += d);
    req.on('end', () => {
      try { proxyOpenAI('/v1/chat/completions', JSON.parse(body), res); }
      catch(e) { res.writeHead(400); res.end(JSON.stringify({ error: e.message })); }
    });
    return;
  }

  // Proxy: TTS
  if (req.method === 'POST' && req.url === '/api/tts') {
    let body = '';
    req.on('data', d => body += d);
    req.on('end', () => {
      try { proxyTTS(JSON.parse(body), res); }
      catch(e) { res.writeHead(400); res.end(JSON.stringify({ error: e.message })); }
    });
    return;
  }

  // Proxy: Whisper STT
  if (req.method === 'POST' && req.url === '/api/stt') {
    const chunks = [];
    req.on('data', d => chunks.push(d));
    req.on('end', () => {
      const buf = Buffer.concat(chunks);
      proxyWhisper(buf, req.headers['content-type'], res);
    });
    return;
  }


  // PWA Manifest
  if (req.url === '/manifest.json') {
    res.writeHead(200, { 'Content-Type': 'application/manifest+json' });
    res.end(`{
  "name": "WorkInGreece Διερμηνέας",
  "short_name": "Διερμηνέας",
  "description": "AI Διερμηνέας για κάθε χώρο εργασίας",
  "start_url": "/",
  "display": "standalone",
  "background_color": "#0f1117",
  "theme_color": "#0f1117",
  "orientation": "portrait",
  "icons": [
    {
      "src": "/icon-192.jpg",
      "sizes": "192x192",
      "type": "image/jpeg"
    },
    {
      "src": "/icon-512.jpg",
      "sizes": "512x512",
      "type": "image/jpeg"
    }
  ]
}`);
    return;
  }

  // Service Worker
  if (req.url === '/sw.js') {
    res.writeHead(200, { 'Content-Type': 'application/javascript' });
    res.end(`const CACHE_NAME = 'workingreece-v1';
self.addEventListener('install', e => {
  self.skipWaiting();
});
self.addEventListener('activate', e => {
  e.waitUntil(self.clients.claim());
});
self.addEventListener('fetch', e => {
  // Only cache GET requests to same origin
  if (e.request.method !== 'GET') return;
  if (e.request.url.includes('/api/')) return;
  if (e.request.url.includes('wss://') || e.request.url.includes('ws://')) return;
  e.respondWith(
    fetch(e.request).catch(() => caches.match(e.request))
  );
});`);
    return;
  }

  // App Icon
  if (req.url === '/icon-192.jpg' || req.url === '/icon-512.jpg') {
    const iconBuf = Buffer.from('', 'base64');
    res.writeHead(200, { 'Content-Type': 'image/jpeg' });
    res.end(iconBuf);
    return;
  }


  // Login page
  if (req.url === '/login') {
    res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
    res.end(require('fs').readFileSync(__dirname + '/login.html'));
    return;
  }

  // Health check
  if (req.url === '/health') {
    res.writeHead(200, { 'Content-Type': 'application/json' });
    res.end(JSON.stringify({ status: 'ok', rooms: Object.keys(rooms).length }));
    return;
  }

  // Serve HTML app
  if (req.url === '/' || req.url === '/index.html') {
    res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
    res.end(require('fs').readFileSync(__dirname + '/index.html'));
    return;
  }

  res.writeHead(404);
  res.end('Not found');
});

const wss = new WebSocketServer({ server });

// Rooms: { roomCode: { A: ws, B: ws } }
const rooms = {};

function generateCode() {
  return Math.floor(1000 + Math.random() * 9000).toString();
}

wss.on('connection', (ws) => {
  let myRoom = null;
  let mySide = null;

  ws.on('message', (data) => {
    let msg;
    try { msg = JSON.parse(data); } catch { return; }

    if (msg.type === 'create') {
      let code = generateCode();
      while (rooms[code]) code = generateCode();
      rooms[code] = { A: ws, B: null };
      myRoom = code;
      mySide = 'A';
      ws.send(JSON.stringify({ type: 'created', code }));
      console.log(`Room ${code} created`);
    }

    else if (msg.type === 'join') {
      const code = msg.code;
      if (!rooms[code]) {
        ws.send(JSON.stringify({ type: 'error', message: 'Λάθος κωδικός δωματίου' }));
        return;
      }
      if (rooms[code].B) {
        ws.send(JSON.stringify({ type: 'error', message: 'Το δωμάτιο είναι γεμάτο' }));
        return;
      }
      rooms[code].B = ws;
      myRoom = code;
      mySide = 'B';
      ws.send(JSON.stringify({ type: 'joined', code }));
      if (rooms[code].A && rooms[code].A.readyState === 1) {
        rooms[code].A.send(JSON.stringify({ type: 'partner_joined' }));
      }
      console.log(`Room ${code}: B joined`);
    }

    else if (msg.type === 'translation') {
      if (!myRoom || !rooms[myRoom]) return;
      const targetSide = mySide === 'A' ? 'B' : 'A';
      const target = rooms[myRoom][targetSide];
      if (target && target.readyState === 1) {
        target.send(JSON.stringify({
          type: 'play_translation',
          text: msg.text,
          voice: msg.voice,
          transcript: msg.transcript
        }));
      }
    }

    else if (msg.type === 'ping') {
      ws.send(JSON.stringify({ type: 'pong' }));
    }
  });

  ws.on('close', () => {
    if (!myRoom || !rooms[myRoom]) return;
    const other = mySide === 'A' ? 'B' : 'A';
    const otherWs = rooms[myRoom][other];
    if (otherWs && otherWs.readyState === 1) {
      otherWs.send(JSON.stringify({ type: 'partner_left' }));
    }
    rooms[myRoom][mySide] = null;
    if (!rooms[myRoom].A && !rooms[myRoom].B) {
      delete rooms[myRoom];
      console.log(`Room ${myRoom} deleted`);
    }
    console.log(`Room ${myRoom}: ${mySide} disconnected`);
  });

  ws.on('error', (err) => console.error('WS error:', err.message));
});

server.listen(PORT, () => {
  console.log(`WorkInGreece Interpreter running on port ${PORT}`);
});
